# Prime Number Checker Program

def is_prime(n):
    """Check if a number is prime."""
    if n <= 1:
        return False  # 1 is not a prime number
    if n == 2:
        return True  # 2 is the smallest prime number
    if n % 2 == 0:
        return False  # Even numbers greater than 2 are not prime
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

def get_positive_integer_input():
    """Prompt the user for a positive integer and handle invalid inputs."""
    while True:
        try:
            num = int(input("Enter a positive integer: "))
            if num > 0:
                return num
            else:
                print("Please enter a positive integer only.")
        except ValueError:
            print("Invalid input. Please enter an integer.")

def main():
    """Main function to run the prime number checking program."""
    print("Welcome to the Prime Number Checker!")
    number = get_positive_integer_input()

    if is_prime(number):
        print(f"{number} is a prime number.")
    else:
        print(f"{number} is not a prime number.")

if __name__ == "__main__":
    main()
```

### Explanation:
- **`is_prime(n)`**: Checks if a number is prime by testing divisibility up to the square root of `n`.
- **`get_positive_integer_input()`**: Ensures the user inputs a valid positive integer with error handling.
- **`main()`**: Runs the program, prompting the user and displaying results.

This code ensures a user-friendly interface, handles invalid inputs, and clearly indicates whether the number is prime.

